import { beforeEach, describe, it, expect } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('observe()', () => {
		it('queues initial observations asynchronously in target order.', async () => {
			const entries: IntersectionObserverEntry[] = [];
			const first = document.createElement('div');
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver((records) => entries.push(...records), {});

			observer.observe(first);
			observer.observe(div);
			expect(entries).toEqual([]);
			await Promise.resolve();
			expect(entries.map((entry) => entry.target)).toEqual([first, div]);
		});
	});

	describe('unobserve()', () => {
		it('stops future entries.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {});

			observer.observe(div);
			observer.unobserve(div);
			await Promise.resolve();
			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('disconnect()', () => {
		it('stops delivery and clears queued records.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {});

			observer.observe(div);
			observer.disconnect();
			await Promise.resolve();
			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('takeRecords()', () => {
		it('returns and clears queued entries.', () => {
			const observer = new window.IntersectionObserver(() => {});
			const div = document.createElement('div');

			observer.observe(div);
			expect(observer.takeRecords()).toHaveLength(1);
			expect(observer.takeRecords()).toEqual([]);
		});
	});

	describe('options and geometry', () => {
		it('normalizes rootMargin and thresholds.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 5%',
				threshold: [1, 0.5, 0.5, 0]
			});
			expect(observer.root).toBeNull();
			expect(observer.rootMargin).toBe('10px 5% 10px 5%');
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});

		it('calculates root margins and threshold crossings from client rectangles.', async () => {
			const root = document.createElement('div');
			const target = document.createElement('div');
			let targetRect = new DOMRect(110, 10, 20, 20);
			root.getBoundingClientRect = () => new DOMRect(0, 0, 100, 100);
			target.getBoundingClientRect = () => targetRect;
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, {
				root,
				rootMargin: '0px 20px',
				threshold: 0.5
			});

			observer.observe(target);
			await Promise.resolve();
			expect(callback.mock.calls[0][0][0].intersectionRatio).toBe(0.5);
			targetRect = new DOMRect(130, 10, 20, 20);
			target.setAttribute('data-geometry-changed', '');
			await Promise.resolve();
			await Promise.resolve();
			expect(callback.mock.calls[1][0][0].intersectionRatio).toBe(0);
		});

		it('handles zero-area targets and rejects invalid inputs.', async () => {
			const target = document.createElement('div');
			target.getBoundingClientRect = () => new DOMRect(10, 10, 0, 0);
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			observer.observe(target);
			await Promise.resolve();
			expect(callback.mock.calls[0][0][0].intersectionRatio).toBe(1);
			expect(() => new window.IntersectionObserver(null as never)).toThrow(TypeError);
			expect(() => new window.IntersectionObserver(() => {}, { rootMargin: '1em' })).toThrow(SyntaxError);
			expect(() => new window.IntersectionObserver(() => {}, { threshold: 2 })).toThrow(RangeError);
			expect(() => observer.observe(null as never)).toThrow(TypeError);
		});
	});
});

